primeCheck:
import math, strformat

proc isPrime(n: int64): bool =
  if n <= 1: return false
  if n <= 3: return true
  if n mod 2 == 0 or n mod 3 == 0: return false

  let limit = int64(sqrt(float(n)))
  var i: int64 = 5
  while i <= limit:
    if n mod i == 0 or n mod (i + 2) == 0:
      return false
    i += 6
  return true

let numbersToCheck = [2'i64, 3, 4, 17, 25, 29, 97, 104729]

for num in numbersToCheck:
  if isPrime(num):
    echo fmt"{num} is prime."
  else:
    echo fmt"{num} is not prime."

readFile:
import os, strformat

let filename = "nim_read_test.txt"

# Create a dummy file for reading
try:
  writeFile(filename, "First line from Nim.\nSecond line.")
  echo fmt"Created dummy file: {filename}"
except IO_Error as e:
  echo fmt"Error creating file: {e.msg}"
  quit()

echo fmt"\n--- Reading file '{filename}' ---"
if fileExists(filename):
  try:
    # Idiomatic way to read line by line
    var i = 1
    for line in lines(filename):
      echo fmt"Line {i}: {line}"
      i += 1
  except IO_Error as e:
    echo fmt"Error reading file: {e.msg}"
else:
  echo "Error: File not found."
